import React, { useState } from 'react';
import { GoogleOAuthProvider, useGoogleLogin } from '@react-oauth/google';
import './App.css';
import WordCloud from './components/WordCloud';

const stopWords = new Set([
  'the','and','for','you','that','with','this','from','are','was','have','but','not','your','can','will','just','its','our','all','any','out','get','got','too','had','her','his','she','him','they','them','their','there','here','who','what','when','where','why','how','been','were','than','then','about','into','over','under','more','most','some','such','only','very','much','many','may','might','should','could','would','also','email','message'
]);

function decodeBase64Url(data) {
  if (!data) return '';
  let base64 = data.replace(/-/g, '+').replace(/_/g, '/');
  while (base64.length % 4) base64 += '=';
  try {
    return atob(base64);
  } catch {
    return '';
  }
}

function extractBodyText(payload) {
  if (!payload) return '';

  if (payload.body?.data) {
    return decodeBase64Url(payload.body.data);
  }

  if (Array.isArray(payload.parts)) {
    const partsText = payload.parts
      .map((part) => extractBodyText(part))
      .filter(Boolean)
      .join(' ');
    return partsText;
  }

  return '';
}

function buildWordCounts(emails) {
  const counts = {};
  const text = emails
    .map((e) => [e.subject, e.from, e.body].filter(Boolean).join(' '))
    .join(' ')
    .toLowerCase()
    .replace(/[^a-z0-9\s]/g, ' ');

  const tokens = text.split(/\s+/).filter((t) => t.length > 1 && !stopWords.has(t));

  tokens.forEach((token) => {
    counts[token] = (counts[token] || 0) + 1;
  });

  return counts;
}

function AppInner() {
  const [authenticated, setAuthenticated] = useState(false);
  const [realWords, setRealWords] = useState({});
  const [emails, setEmails] = useState([]);
  const [loading, setLoading] = useState(false);

  const login = useGoogleLogin({
    flow: 'implicit',
    scope: 'https://www.googleapis.com/auth/gmail.readonly',
    onSuccess: async (tokenResponse) => {
      try {
        setLoading(true);

        const listRes = await fetch('https://gmail.googleapis.com/gmail/v1/users/me/messages?maxResults=15', {
          headers: {
            Authorization: `Bearer ${tokenResponse.access_token}`,
          },
        });

        const listData = await listRes.json();
        const fetchedEmails = [];

        for (const msg of listData.messages || []) {
          const msgRes = await fetch(
            `https://gmail.googleapis.com/gmail/v1/users/me/messages/${msg.id}?format=full`,
            {
              headers: {
                Authorization: `Bearer ${tokenResponse.access_token}`,
              },
            }
          );

          const msgData = await msgRes.json();
          const headers = msgData.payload?.headers || [];
          const subject = headers.find((h) => h.name === 'Subject')?.value || '';
          const from = headers.find((h) => h.name === 'From')?.value || '';
          const body = extractBodyText(msgData.payload) || msgData.snippet || '';

          fetchedEmails.push({
            id: msg.id,
            subject,
            from,
            body,
            snippet: msgData.snippet || '',
          });
        }

        const counts = buildWordCounts(fetchedEmails);
        setEmails(fetchedEmails);
        setRealWords(counts);
        setAuthenticated(true);
      } catch (err) {
        console.error(err);
      } finally {
        setLoading(false);
      }
    },
    onError: () => {
      console.log('Login Failed');
    },
  });

  return (
    <div className="app" style={{ textAlign: 'center', padding: '20px' }}>
      <h1>CloudScope</h1>

      {!authenticated ? (
        <button onClick={() => login()} style={{ padding: '10px 16px', fontSize: '16px' }}>
          Sign in with Google
        </button>
      ) : loading ? (
        <div>Loading your inbox...</div>
      ) : (
        <WordCloud words={realWords} emailData={emails} />
      )}
    </div>
  );
}

export default function App() {
  return (
    <GoogleOAuthProvider clientId="613649107764-a62ejns04vkh5lc9sdc412idbpkfrn88.apps.googleusercontent.com">
      <AppInner />
    </GoogleOAuthProvider>
  );
}
